SELECT COUNT(download_id) AS total_downloads
FROM resource_downloads
WHERE user_id = 1;

SELECT COUNT(resource_id) AS total_views
  FROM resource_views
  WHERE resource_id = 1;

SELECT COUNT(*) AS total_views
FROM resource_views
WHERE resource_id = 1;

SELECT title
FROM resources
WHERE resource_id IN (
  SELECT resource_id
  FROM resource_downloads
);

SELECT title, views_count
FROM resources
ORDER BY views_count DESC;
